// SPDX-License-Identifier: MIT
pragma solidity ^0.8.0;

/**
 * @title MerchantFactory (Tron TVM Edition)
 * @notice Factory for deploying SplitterLogic clones on the Tron network.
 *
 * Differences from EVM version:
 * - Uses manual Clones library (EIP-1167 works on TVM)
 * - No OpenZeppelin Ownable/Pausable imports (bundled inline for TVM compatibility)
 * - Compatible with Solidity ^0.8.0 on TVM
 */

interface ISplitterLogic {
    function initialize(address _merchantAddress, address _factory, address _authorizer) external;
    function setAuthorizer(address _newAuthorizer) external;
    function rescueToken(address token, uint256 amount) external;
}

interface ITRC20 {
    function transfer(address recipient, uint256 amount) external returns (bool);
}

library Clones {
    function clone(address implementation) internal returns (address instance) {
        /// @solidity memory-safe-assembly
        assembly {
            let ptr := mload(0x40)
            mstore(ptr, 0x3d602d80600a3d3981f3363d3d373d3d3d363d73000000000000000000000000)
            mstore(add(ptr, 0x14), shl(0x60, implementation))
            mstore(add(ptr, 0x28), 0x5af43d82803e903d91602b57fd5bf30000000000000000000000000000000000)
            instance := create(0, ptr, 0x37)
            mstore(0x40, add(ptr, 0x37))
        }
        require(instance != address(0), "ERC1167: create failed");
    }
}

contract MerchantFactory {
    // === Ownership ===
    address public owner;

    modifier onlyOwner() {
        require(msg.sender == owner, "Not owner");
        _;
    }

    function transferOwnership(address newOwner) external onlyOwner {
        require(newOwner != address(0), "Zero address");
        owner = newOwner;
    }

    // === Pausable ===
    bool private _paused;

    function paused() public view returns (bool) {
        return _paused;
    }

    function pause() external onlyOwner {
        _paused = true;
    }

    function unpause() external onlyOwner {
        _paused = false;
    }

    // === Factory State ===
    address public developerAddress;
    uint256 public feeBps = 10; // 0.1%
    address public splitterLogicImpl;
    address public authorizer;

    mapping(address => bool) public allowedRouters;
    mapping(address => address) public merchantSplitters;
    mapping(bytes32 => bool) public globalProcessedPayments;
    mapping(address => bool) public isClone;

    // Timelock for rescue operations
    uint256 public constant TIMELOCK_DELAY = 2 days;
    mapping(bytes32 => uint256) public rescueRequests;
    mapping(bytes32 => bytes) public rescueData;

    event RescueTokenProposed(bytes32 indexed requestId, address indexed clone, address token, uint256 amount, uint256 executeTime);
    event RescueTokenExecuted(bytes32 indexed requestId, address indexed clone, address token, uint256 amount);
    event RescueTokenCancelled(bytes32 indexed requestId);
    event MerchantCloneDeployed(address indexed merchant, address cloneAddress);
    event PaymentRecorded(bytes32 indexed paymentId, address indexed clone, address indexed token, uint256 amount);
    event AuthorizerUpdated(address indexed newAuthorizer);
    event DefaultAuthorizerSet(address indexed authorizer);

    constructor(address _devAddress, address _splitterLogicImpl) {
        require(_devAddress != address(0), "Invalid dev address");
        require(_splitterLogicImpl != address(0), "Invalid impl");
        owner = msg.sender;
        developerAddress = _devAddress;
        splitterLogicImpl = _splitterLogicImpl;
        authorizer = msg.sender;
        emit DefaultAuthorizerSet(msg.sender);
    }

    function createMerchantSplitter(address merchant) external returns (address) {
        return createMerchantSplitter(merchant, address(0));
    }

    function createMerchantSplitter(address merchant, address _authorizer) public returns (address) {
        require(merchantSplitters[merchant] == address(0), "Merchant already has a clone");

        address cloneAddr = Clones.clone(splitterLogicImpl);

        address auth = _authorizer != address(0) ? _authorizer : authorizer;
        ISplitterLogic(cloneAddr).initialize(merchant, address(this), auth);

        merchantSplitters[merchant] = cloneAddr;
        isClone[cloneAddr] = true;

        emit MerchantCloneDeployed(merchant, cloneAddr);
        return cloneAddr;
    }

    function recordPayment(bytes32 paymentId, address token, uint256 amount) external {
        require(isClone[msg.sender], "Caller is not a registered clone");
        require(!globalProcessedPayments[paymentId], "Payment already processed");
        globalProcessedPayments[paymentId] = true;
        emit PaymentRecorded(paymentId, msg.sender, token, amount);
    }

    function setFeeBps(uint256 _bps) external onlyOwner {
        feeBps = _bps;
    }

    function setDeveloperAddress(address _newDev) external onlyOwner {
        developerAddress = _newDev;
    }

    function setAuthorizer(address _newAuthorizer) external onlyOwner {
        authorizer = _newAuthorizer;
        emit AuthorizerUpdated(_newAuthorizer);
    }

    function updateCloneAuthorizer(address _clone, address _newAuthorizer) external onlyOwner {
        require(isClone[_clone], "Not a clone");
        ISplitterLogic(_clone).setAuthorizer(_newAuthorizer);
    }

    function merchantRescueToken(address token, uint256 amount) external {
        address _clone = merchantSplitters[msg.sender];
        require(_clone != address(0), "No clone for sender");
        ISplitterLogic(_clone).rescueToken(token, amount);
    }

    function toggleRouterAllowlist(address router, bool status) external onlyOwner {
        allowedRouters[router] = status;
    }

    function isRouterAllowed(address router) external view returns (bool) {
        return allowedRouters[router];
    }

    function proposeRescueToken(address _clone, address token, uint256 amount) external onlyOwner returns (bytes32 requestId) {
        require(isClone[_clone], "Not a clone");
        requestId = keccak256(abi.encodePacked(_clone, token, amount, block.timestamp));
        rescueRequests[requestId] = block.timestamp + TIMELOCK_DELAY;
        rescueData[requestId] = abi.encode(_clone, token, amount);
        emit RescueTokenProposed(requestId, _clone, token, amount, rescueRequests[requestId]);
    }

    function executeRescueToken(bytes32 requestId) external onlyOwner {
        uint256 executeTime = rescueRequests[requestId];
        require(executeTime != 0, "Invalid request");
        require(block.timestamp >= executeTime, "Timelock active");

        (address _clone, address token, uint256 amount) = abi.decode(rescueData[requestId], (address, address, uint256));
        ISplitterLogic(_clone).rescueToken(token, amount);
        emit RescueTokenExecuted(requestId, _clone, token, amount);

        delete rescueRequests[requestId];
        delete rescueData[requestId];
    }

    function cancelRescueToken(bytes32 requestId) external onlyOwner {
        require(rescueRequests[requestId] != 0, "Invalid request");
        emit RescueTokenCancelled(requestId);
        delete rescueRequests[requestId];
        delete rescueData[requestId];
    }
}

