// SPDX-License-Identifier: MIT
pragma solidity ^0.8.0;

/**
 * @title SplitterLogic (Tron TVM Edition)
 * @notice Payment splitter for TRC-20 tokens on the Tron network.
 *
 * Differences from EVM version:
 * - No EIP-712: Uses simple keccak256 + ecrecover for signature verification
 * - No Initializable proxy: Uses constructor-based initialization (Tron CREATE is cheap)
 * - TRC-20 is interface-identical to IERC20
 * - Compatible with Solidity ^0.8.0 on TVM
 */

interface ITRC20 {
    function transferFrom(address sender, address recipient, uint256 amount) external returns (bool);
    function transfer(address recipient, uint256 amount) external returns (bool);
    function balanceOf(address account) external view returns (uint256);
    function approve(address spender, uint256 amount) external returns (bool);
}

interface ISplitterFactory {
    function developerAddress() external view returns (address);
    function feeBps() external view returns (uint256);
    function isRouterAllowed(address router) external view returns (bool);
    function paused() external view returns (bool);
    function recordPayment(bytes32 paymentId, address token, uint256 amount) external;
    function owner() external view returns (address);
}

contract SplitterLogic {
    address public merchantAddress;
    address public factory;
    address public authorizer;
    bool private _initialized;
    bool private _locked;

    event PaymentProcessed(
        bytes32 indexed paymentId,
        address indexed tokenIn,
        address indexed tokenOut,
        uint256 amountIn,
        uint256 merchantReceived,
        uint256 devFee
    );
    event AuthorizerUpdated(address indexed newAuthorizer);

    error AlreadyInitialized();
    error ZeroAddress();
    error PaymentExpired();
    error InvalidSignature();
    error FactoryPaused();
    error RouterNotAllowed();
    error SlippageExceeded();
    error TransferFailed();
    error OnlyFactory();
    error ReentrantCall();

    modifier nonReentrant() {
        if (_locked) revert ReentrantCall();
        _locked = true;
        _;
        _locked = false;
    }

    function initialize(address _merchantAddress, address _factory, address _authorizer) public {
        if (_initialized) revert AlreadyInitialized();
        if (_merchantAddress == address(0) || _factory == address(0)) revert ZeroAddress();

        merchantAddress = _merchantAddress;
        factory = _factory;
        authorizer = _authorizer;
        _initialized = true;
    }

    /**
     * @notice Process a direct TRC-20 payment with fee splitting
     * @param paymentId Unique payment identifier
     * @param token TRC-20 token address
     * @param amount Amount in smallest unit (sun for TRX, 1e-6 for USDT-TRC20)
     * @param expiry Unix timestamp after which the payment expires
     * @param signature keccak256 signature from authorizer
     */
    function payDirect(
        bytes32 paymentId,
        address token,
        uint256 amount,
        uint256 expiry,
        bytes calldata signature
    ) external nonReentrant {
        if (block.timestamp > expiry) revert PaymentExpired();

        _verifySignature(paymentId, token, amount, expiry, signature);

        ISplitterFactory fac = ISplitterFactory(factory);
        if (fac.paused()) revert FactoryPaused();

        uint256 feeBps = fac.feeBps();
        uint256 fee = (amount * feeBps) / 10000;
        uint256 merchantAmount = amount - fee;

        // Record payment at factory level (prevents double spend)
        fac.recordPayment(paymentId, token, amount);

        if (!ITRC20(token).transferFrom(msg.sender, fac.developerAddress(), fee)) revert TransferFailed();
        if (!ITRC20(token).transferFrom(msg.sender, merchantAddress, merchantAmount)) revert TransferFailed();

        emit PaymentProcessed(paymentId, token, token, amount, merchantAmount, fee);
    }

    /**
     * @notice Process a payment with token swap via DEX (SunSwap/JustSwap)
     * @param paymentId Unique payment identifier
     * @param tokenIn Input TRC-20 token
     * @param tokenOut Output TRC-20 token (what merchant receives)
     * @param amountIn Amount of input token
     * @param minAmountOut Minimum output amount (slippage protection)
     * @param expiry Expiry timestamp
     * @param router DEX router address (SunSwap V2, etc.)
     * @param spender Spender address for approval
     * @param swapData Calldata for the DEX swap
     * @param signature Authorizer signature
     */
    function payWithSwap(
        bytes32 paymentId,
        address tokenIn,
        address tokenOut,
        uint256 amountIn,
        uint256 minAmountOut,
        uint256 expiry,
        address router,
        address spender,
        bytes calldata swapData,
        bytes calldata signature
    ) external nonReentrant {
        if (block.timestamp > expiry) revert PaymentExpired();

        _verifySignature(paymentId, tokenIn, amountIn, expiry, signature);

        ISplitterFactory fac = ISplitterFactory(factory);
        if (fac.paused()) revert FactoryPaused();
        if (!fac.isRouterAllowed(router)) revert RouterNotAllowed();

        if (!ITRC20(tokenIn).transferFrom(msg.sender, address(this), amountIn)) revert TransferFailed();
        ITRC20(tokenIn).approve(spender, amountIn);

        uint256 balanceBefore = ITRC20(tokenOut).balanceOf(address(this));
        (bool success, ) = router.call(swapData);
        if (!success) revert TransferFailed();

        uint256 receivedOut = ITRC20(tokenOut).balanceOf(address(this)) - balanceBefore;
        if (receivedOut < minAmountOut) revert SlippageExceeded();

        // Sanity: received at least 50% of input (prevents catastrophic swap failures)
        if (tokenIn != tokenOut && receivedOut < (amountIn / 2)) revert SlippageExceeded();

        uint256 feeBps = fac.feeBps();
        uint256 fee = (receivedOut * feeBps) / 10000;
        uint256 merchantAmount = receivedOut - fee;

        fac.recordPayment(paymentId, tokenOut, receivedOut);

        if (!ITRC20(tokenOut).transfer(fac.developerAddress(), fee)) revert TransferFailed();
        if (!ITRC20(tokenOut).transfer(merchantAddress, merchantAmount)) revert TransferFailed();

        emit PaymentProcessed(paymentId, tokenIn, tokenOut, amountIn, merchantAmount, fee);
    }

    /**
     * @notice Tron-compatible signature verification (no EIP-712).
     * Uses keccak256(abi.encodePacked(paymentId, token, amount, expiry)) + ecrecover.
     */
    function _verifySignature(
        bytes32 paymentId,
        address token,
        uint256 amount,
        uint256 expiry,
        bytes calldata signature
    ) internal view {
        if (authorizer == address(0)) return; // No signature required if authorizer not set

        bytes32 messageHash = keccak256(
            abi.encodePacked(
                "\x19Tron Signed Message:\n32",
                keccak256(abi.encodePacked(paymentId, token, amount, expiry))
            )
        );

        (bytes32 r, bytes32 s, uint8 v) = _splitSignature(signature);
        address recovered = ecrecover(messageHash, v, r, s);

        if (recovered != authorizer) revert InvalidSignature();
    }

    function _splitSignature(bytes calldata sig) internal pure returns (bytes32 r, bytes32 s, uint8 v) {
        require(sig.length == 65, "Invalid signature length");
        assembly {
            r := calldataload(sig.offset)
            s := calldataload(add(sig.offset, 32))
            v := byte(0, calldataload(add(sig.offset, 64)))
        }
        if (v < 27) v += 27;
    }

    function setAuthorizer(address _newAuthorizer) external {
        if (msg.sender != factory) revert OnlyFactory();
        authorizer = _newAuthorizer;
        emit AuthorizerUpdated(_newAuthorizer);
    }

    function rescueToken(address token, uint256 amount) external {
        if (msg.sender != factory) revert OnlyFactory();
        address owner = ISplitterFactory(factory).owner();
        if (!ITRC20(token).transfer(owner, amount)) revert TransferFailed();
    }
}

